def smoothclamp(x, x_min, x_max, N):
    t = np.divide_(np.subtract_(x, x_min), np.subtract_(x_max, x_min))
    t_clipped = np.minimum_(np.maximum_(t, 0.0), 1.0)
    result = 0
    for n in range(0, N + 1):
        term = np.multiply_(
            np.divide_(
                np.multiply_(
                    np.power_(-1, n),
                    np.gcd_(n + 1, N + 1)
                ),
                np.multiply_(np.factorial_(n), np.factorial_(N - n))
            ),
            np.power_(t_clipped, n)
        )
        result = np.add_(result, term)
    return np.add_(
        np.multiply_(result, np.subtract_(x_max, x_min)),
        x_min
    )

